#include "BibleFrame.h"\n#include <wx/sizer.h>\n#include <wx/stattext.h>\n\nwxBEGIN_EVENT_TABLE(BibleFrame, wxFrame)\n    EVT_CHOICE(wxID_ANY, BibleFrame::OnBookSelected)\n    EVT_SPINCTRL(wxID_ANY, BibleFrame::OnChapterSelected)\n    EVT_LIST_ITEM_SELECTED(wxID_ANY, BibleFrame::OnVersesSelected)\nwxEND_EVENT_TABLE()\n\nBibleFrame::BibleFrame(const wxString& title)\n    : wxFrame(nullptr, wxID_ANY, title, wxDefaultPosition, wxSize(800, 600)) {\n    CreateUI();\n    LoadBibleData();\n}\n\nvoid BibleFrame::CreateUI() {\n    wxPanel* panel = new wxPanel(this);\n    wxBoxSizer* mainSizer = new wxBoxSizer(wxVERTICAL);\n\n    wxBoxSizer* controlSizer = new wxBoxSizer(wxHORIZONTAL);\n    controlSizer->Add(new wxStaticText(panel, wxID_ANY, "Book:"), 0, wxALL | wxALIGN_CENTER_VERTICAL, 5);\n    m_bookChoice = new wxChoice(panel, wxID_ANY);\n    controlSizer->Add(m_bookChoice, 1, wxALL | wxEXPAND, 5);\n\n    controlSizer->Add(new wxStaticText(panel, wxID_ANY, "Chapter:"), 0, wxALL | wxALIGN_CENTER_VERTICAL, 5);\n    m_chapterSpin = new wxSpinCtrl(panel, wxID_ANY, "1", wxDefaultPosition, wxSize(80, -1), 0, 1, 100);\n    controlSizer->Add(m_chapterSpin, 0, wxALL | wxEXPAND, 5);\n\n    mainSizer->Add(controlSizer, 0, wxEXPAND | wxALL, 5);\n\n    wxStaticBoxSizer* versesBox = new wxStaticBoxSizer(wxVERTICAL, panel, "Verses");\n    m_versesList = new wxListCtrl(panel, wxID_ANY, wxDefaultPosition, wxDefaultSize, wxLC_REPORT | wxLC_SINGLE_SEL);\n    m_versesList->AppendColumn("Verse", wxLIST_FORMAT_LEFT, 100);\n    m_versesList->AppendColumn("Text", wxLIST_FORMAT_LEFT, 500);\n    versesBox->Add(m_versesList, 1, wxEXPAND | wxALL, 5);\n    mainSizer->Add(versesBox, 1, wxEXPAND | wxALL, 5);\n\n    wxStaticBoxSizer* detailsBox = new wxStaticBoxSizer(wxVERTICAL, panel, "Full Verse");\n    m_verseText = new wxTextCtrl(panel, wxID_ANY, "", wxDefaultPosition, wxSize(-1, 100), wxTE_MULTILINE | wxTE_READONLY | wxTE_WORDWRAP);\n    detailsBox->Add(m_verseText, 1, wxEXPAND | wxALL, 5);\n    mainSizer->Add(detailsBox, 1, wxEXPAND | wxALL, 5);\n\n    panel->SetSizer(mainSizer);\n}\n\nvoid BibleFrame::LoadBibleData() {\n    wxArrayString books;\n    books.Add("Genesis");\n    books.Add("Exodus");\n    books.Add("Leviticus");\n    books.Add("Numbers");\n    books.Add("Deuteronomy");\n    books.Add("Joshua");\n    books.Add("Judges");\n    books.Add("Ruth");\n    books.Add("1 Samuel");\n    books.Add("2 Samuel");\n\n    for (const auto& book : books) {\n        m_bookChoice->Append(book);\n    }\n\n    m_bookChoice->SetSelection(0);\n\n    m_verses.push_back({0, 1, 1, "In the beginning God created the heavens and the earth."});\n    m_verses.push_back({0, 1, 2, "Now the earth was formless and empty, darkness was over the surface of the deep, and the Spirit of God was hovering over the waters."});\n    m_verses.push_back({0, 1, 3, "And God said, 'Let there be light:' and there was light."});\n}\n\nvoid BibleFrame::OnBookSelected(wxCommandEvent& event) {\n    int selection = m_bookChoice->GetSelection();\n    m_versesList->DeleteAllItems();\n    m_verseText->Clear();\n}\n\nvoid BibleFrame::OnChapterSelected(wxCommandEvent& event) {\n    int chapter = m_chapterSpin->GetValue();\n    m_versesList->DeleteAllItems();\n    m_verseText->Clear();\n\n    long index = 0;\n    for (const auto& verse : m_verses) {\n        if (verse.chapter == chapter) {\n            m_versesList->InsertItem(index, wxString::Format("%d:%d", verse.chapter, verse.verse));\n            m_versesList->SetItem(index, 1, verse.text);\n            index++;\n        }\n    }\n}\n\nvoid BibleFrame::OnVersesSelected(wxListEvent& event) {\n    long index = event.GetIndex();\n    if (index >= 0 && index < (long)m_verses.size()) {\n        m_verseText->SetValue(m_verses[index].text);\n    }\n}